import { describe, it, expect, beforeEach } from 'vitest'
import { useDecorationStore } from './decorationStore'
import type { Watermark, QRConfig } from '../types'

const defaultQRConfig: QRConfig = {
  enabled: false,
  content: '',
  size: 40,
  position: 'bottom-right',
