package pdf

import (
	"bytes"
	"fmt"
	"os"
	"runtime"
	"strings"

	"github.com/jung-kurt/gofpdf"

	"atena-label/internal/entity"
)

// Generator implements repository.PDFGenerator using gofpdf.
type Generator struct {
	fontPath string // path to a Japanese TrueType font (.ttf)
}

// NewGenerator creates a Generator. fontPath may be empty to use auto-detection.
func NewGenerator(fontPath string) *Generator {
	if fontPath == "" {
		fontPath = detectJapaneseFont()
	}
	return &Generator{fontPath: fontPath}
}

// detectJapaneseFont returns the first usable Japanese TTF/TTC font path found on the system.
func detectJapaneseFont() string {
	var candidates []string
	switch runtime.GOOS {
	case "darwin":
		candidates = []string{
			"/System/Library/Fonts/ヒラギノ明朝 ProN.ttc",
			"/Library/Fonts/Hiragino Mincho ProN W3.otf",
			"/System/Library/Fonts/Hiragino Mincho ProN.ttc",
			"/Library/Fonts/YuMincho.ttc",
		}
	case "windows":
		candidates = []string{
			`C:\Windows\Fonts\msmincho.ttc`,
			`C:\Windows\Fonts\YuMincho.ttc`,
			`C:\Windows\Fonts\mingliu.ttc`,
		}
	default:
		candidates = []string{
			"/usr/share/fonts/truetype/noto/NotoSerifCJK-Regular.ttc",
			"/usr/share/fonts/opentype/noto/NotoSerifCJK-Regular.ttc",
			"/usr/share/fonts/truetype/fonts-japanese-mincho.ttf",
		}
	}
	for _, p := range candidates {
		if _, err := os.Stat(p); err == nil {
			return p
		}
	}
	return ""
}

// GenerateLabelPDF generates an A4 label PDF from the given job data.
// contacts, sender and job.Template drive placement.
// Returns the raw PDF bytes.
func (g *Generator) GenerateLabelPDF(
	job entity.PrintJob,
	contacts []entity.Contact,
	sender *entity.Sender,
) ([]byte, error) {
	pdf := gofpdf.New("P", "mm", "A4", "")
	pdf.SetMargins(0, 0, 0)
	pdf.SetAutoPageBreak(false, 0)

	// Register Japanese font if available.
	hasJFont := g.fontPath != ""
	fontName := "jfont"
	if hasJFont {
		pdf.AddUTF8Font(fontName, "", g.fontPath)
		if err := pdf.Error(); err != nil {
			// Font load failed — fall back to built-in Courier
			hasJFont = false
		}
	}
	setFont := func(size float64) {
		if hasJFont {
			pdf.SetFont(fontName, "", size)
		} else {
			pdf.SetFont("Courier", "", size)
		}
	}

	layout := job.LabelLayout
	tmpl := job.Template

	labelsPerPage := layout.Columns * layout.Rows
	if labelsPerPage == 0 {
		return nil, fmt.Errorf("invalid label layout: columns=%d rows=%d", layout.Columns, layout.Rows)
	}

	for i, contact := range contacts {
		if i%labelsPerPage == 0 {
			pdf.AddPage()
		}

		pageIdx := i % labelsPerPage
		col := pageIdx % layout.Columns
		row := pageIdx / layout.Columns

		// Top-left corner of this label on the page (mm).
		originX := layout.MarginLeft + float64(col)*(layout.LabelWidth+layout.GapX)
		originY := layout.MarginTop + float64(row)*(layout.LabelHeight+layout.GapY)

		// Draw watermark background.
		if job.Watermark != nil && job.Watermark.FilePath != "" {
			drawWatermark(pdf, job.Watermark, originX, originY, layout.LabelWidth, layout.LabelHeight)
		}

		// Draw label content.
		drawLabel(pdf, setFont, &contact, sender, tmpl, originX, originY)

		// Draw QR code.
		if job.QRConfig != nil && job.QRConfig.Enabled && job.QRConfig.Content != "" {
			if err := drawQR(pdf, job.QRConfig, originX, originY, layout.LabelWidth, layout.LabelHeight); err != nil {
				// QR draw failure is non-fatal — log and continue.
				_ = err
			}
		}
	}

	var buf bytes.Buffer
	if err := pdf.Output(&buf); err != nil {
		return nil, fmt.Errorf("pdf output: %w", err)
	}
	return buf.Bytes(), nil
}

// drawWatermark places the watermark image as a background for the label area.
func drawWatermark(pdf *gofpdf.Fpdf, wm *entity.Watermark, x, y, w, h float64) {
	if _, err := os.Stat(wm.FilePath); err != nil {
		return
	}
	imgType := imageType(wm.FilePath)
	opts := gofpdf.ImageOptions{ImageType: imgType, ReadDpi: false}
	pdf.ImageOptions(wm.FilePath, x, y, w, h, false, opts, 0, "")
}

// drawQR generates a QR code and places it in the label at the configured position.
func drawQR(pdf *gofpdf.Fpdf, qr *entity.QRConfig, originX, originY, labelW, labelH float64) error {
	import_qrcode_pkg := func() ([]byte, error) {
		// Import the go-qrcode package via the generator already used in the app.
		// We use the same library directly here to avoid a circular dependency.
		qrcodeLib, err := generateQRPNG(qr.Content, qr.Size)
		return qrcodeLib, err
	}

	pngBytes, err := import_qrcode_pkg()
	if err != nil {
		return fmt.Errorf("generate qr: %w", err)
	}

	// Size in mm (1px ≈ 0.264mm at 96dpi — use qr.Size as mm directly).
	sizeMM := float64(qr.Size) * 0.264583

	var qrX, qrY float64
	switch qr.Position {
	case "top-left":
		qrX = originX + 1
		qrY = originY + 1
	case "top-right":
		qrX = originX + labelW - sizeMM - 1
		qrY = originY + 1
	case "bottom-left":
		qrX = originX + 1
		qrY = originY + labelH - sizeMM - 1
	default: // "bottom-right"
		qrX = originX + labelW - sizeMM - 1
		qrY = originY + labelH - sizeMM - 1
	}

	reader := bytes.NewReader(pngBytes)
	pdf.RegisterImageOptionsReader("qr_"+qr.Position, gofpdf.ImageOptions{ImageType: "PNG"}, reader)
	pdf.ImageOptions("qr_"+qr.Position, qrX, qrY, sizeMM, sizeMM, false, gofpdf.ImageOptions{ImageType: "PNG"}, 0, "")
	return nil
}

// drawLabel renders postal code, recipient name/address and sender info.
func drawLabel(
	pdf *gofpdf.Fpdf,
	setFont func(float64),
	contact *entity.Contact,
	sender *entity.Sender,
	tmpl entity.Template,
	ox, oy float64,
) {
	pdf.SetTextColor(0, 0, 0)

	// --- Postal code ---
	if tmpl.PostalCode != nil && contact.PostalCode != "" {
		setFont(tmpl.PostalCode.FontSize)
		digits := strings.ReplaceAll(contact.PostalCode, "-", "")
		for i, ch := range digits {
			xPos := ox + tmpl.PostalCode.X + float64(i)*tmpl.PostalCode.DigitSpacing
			pdf.SetXY(xPos, oy+tmpl.PostalCode.Y)
			pdf.CellFormat(tmpl.PostalCode.DigitSpacing, tmpl.PostalCode.FontSize*0.4, string(ch), "", 0, "C", false, 0, "")
		}
	}

	// --- Recipient ---
	rec := tmpl.Recipient
	fullName := contact.FamilyName + contact.GivenName
	if contact.Company != "" {
		fullName = contact.Company
		if contact.Department != "" {
			fullName += "\n" + contact.Department
		}
		fullName += "\n" + contact.FamilyName + contact.GivenName
	}
	honorific := contact.Honorific
	if honorific == "" {
		honorific = "様"
	}

	if tmpl.Orientation == "vertical" {
		// Name — vertical (top-to-bottom, right-to-left columns)
		setFont(rec.NameFont)
		drawVerticalText(pdf, fullName+" "+honorific, ox+rec.NameX, oy+rec.NameY, rec.NameFont)

		// Address — vertical
		setFont(rec.AddressFont)
		addr := buildAddress(contact)
		drawVerticalText(pdf, addr, ox+rec.AddressX, oy+rec.AddressY, rec.AddressFont)
	} else {
		// Horizontal layout
		setFont(rec.NameFont)
		pdf.SetXY(ox+rec.NameX, oy+rec.NameY)
		pdf.MultiCell(0, rec.NameFont*0.5, fullName+" "+honorific, "", "L", false)

		setFont(rec.AddressFont)
		pdf.SetXY(ox+rec.AddressX, oy+rec.AddressY)
		pdf.MultiCell(0, rec.AddressFont*0.5, buildAddress(contact), "", "L", false)
	}

	// --- Sender ---
	if sender != nil {
		snd := tmpl.Sender
		senderName := sender.FamilyName + sender.GivenName
		if sender.Company != "" {
			senderName = sender.Company + " " + senderName
		}
		senderAddr := buildSenderAddress(sender)

		if tmpl.Orientation == "vertical" {
			setFont(snd.NameFont)
			drawVerticalText(pdf, senderName, ox+snd.NameX, oy+snd.NameY, snd.NameFont)
			setFont(snd.AddressFont)
			drawVerticalText(pdf, senderAddr, ox+snd.AddressX, oy+snd.AddressY, snd.AddressFont)
		} else {
			setFont(snd.NameFont)
			pdf.SetXY(ox+snd.NameX, oy+snd.NameY)
			pdf.CellFormat(0, snd.NameFont*0.5, senderName, "", 0, "L", false, 0, "")
			setFont(snd.AddressFont)
			pdf.SetXY(ox+snd.AddressX, oy+snd.AddressY)
			pdf.CellFormat(0, snd.AddressFont*0.5, senderAddr, "", 0, "L", false, 0, "")
		}
	}
}

// drawVerticalText places each rune in a vertical column (top-to-bottom).
func drawVerticalText(pdf *gofpdf.Fpdf, text string, x, y, fontSize float64) {
	lineH := fontSize * 0.45 // mm per character line
	for i, ch := range text {
		pdf.SetXY(x, y+float64(i)*lineH)
		pdf.CellFormat(fontSize*0.45, lineH, string(ch), "", 0, "C", false, 0, "")
	}
}

func buildAddress(c *entity.Contact) string {
	parts := []string{}
	if c.PostalCode != "" {
		parts = append(parts, "〒"+c.PostalCode)
	}
	if c.Prefecture != "" {
		parts = append(parts, c.Prefecture)
	}
	if c.City != "" {
		parts = append(parts, c.City)
	}
	if c.Street != "" {
		parts = append(parts, c.Street)
	}
	if c.Building != "" {
		parts = append(parts, c.Building)
	}
	return strings.Join(parts, "")
}

func buildSenderAddress(s *entity.Sender) string {
	parts := []string{}
	if s.PostalCode != "" {
		parts = append(parts, "〒"+s.PostalCode)
	}
	if s.Prefecture != "" {
		parts = append(parts, s.Prefecture)
	}
	if s.City != "" {
		parts = append(parts, s.City)
	}
	if s.Street != "" {
		parts = append(parts, s.Street)
	}
	if s.Building != "" {
		parts = append(parts, s.Building)
	}
	return strings.Join(parts, "")
}

func imageType(path string) string {
	lower := strings.ToLower(path)
	switch {
	case strings.HasSuffix(lower, ".png"):
		return "PNG"
	case strings.HasSuffix(lower, ".jpg") || strings.HasSuffix(lower, ".jpeg"):
		return "JPG"
	default:
		return "PNG"
	}
}

// generateQRPNG generates a QR code PNG from content using go-qrcode.
func generateQRPNG(content string, sizePx int) ([]byte, error) {
	qrcodeLib, err := qrEncode(content, sizePx)
	return qrcodeLib, err
}

